def evaluate(expr: str) -> float:
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c.isdigit() or c == '.':
            j = i
            dot = False
            while j < n and (expr[j].isdigit() or expr[j] == '.'):
                if expr[j] == '.':
                    if dot:
                        raise ValueError("invalid number literal")
                    dot = True
                j += 1
            lit = expr[i:j]
            if lit == '.':
                raise ValueError("invalid number literal")
            tokens.append(('num', float(lit)))
            i = j
        elif c == '*':
            if i + 1 < n and expr[i + 1] == '*':
                tokens.append(('**', '**'))
                i += 2
            else:
                tokens.append(('*', '*'))
                i += 1
        elif c in '+-/()':
            tokens.append((c, c))
            i += 1
        else:
            raise ValueError("illegal character: {!r}".format(c))

    if not tokens:
        raise ValueError("empty expression")

    pos = 0

    def peek():
        return tokens[pos][0] if pos < len(tokens) else None

    def advance():
        nonlocal pos
        tok = tokens[pos]
        pos += 1
        return tok

    def parse_expr():
        value = parse_term()
        while peek() in ('+', '-'):
            op = advance()[0]
            right = parse_term()
            value = value + right if op == '+' else value - right
        return value

    def parse_term():
        value = parse_unary()
        while peek() in ('*', '/'):
            op = advance()[0]
            right = parse_unary()
            value = value * right if op == '*' else value / right
        return value

    def parse_unary():
        if peek() == '-':
            advance()
            return -parse_unary()
        return parse_power()

    def parse_power():
        base = parse_atom()
        if peek() == '**':
            advance()
            exponent = parse_unary()
            return base ** exponent
        return base

    def parse_atom():
        tok = peek()
        if tok == 'num':
            return advance()[1]
        if tok == '(':
            advance()
            value = parse_expr()
            if peek() != ')':
                raise ValueError("unbalanced parentheses")
            advance()
            return value
        raise ValueError("unexpected token")

    result = parse_expr()
    if pos != len(tokens):
        raise ValueError("unexpected trailing tokens")

    result = float(result)
    return result
